import java.util.*;

class UndergroundSystem {
    private Map<Integer, Pair<String, Integer>> checkInData;
    private Map<String, Pair<Integer, Integer>> travelData;

    public UndergroundSystem() {
        checkInData = new HashMap<>();
        travelData = new HashMap<>();
    }

    public void checkIn(int id, String stationName, int t) {
        checkInData.put(id, new Pair<>(stationName, t));
    }

    public void checkOut(int id, String stationName, int t) {
        String startStation = checkInData.get(id).getKey();
        int startTime = checkInData.get(id).getValue();
        String route = startStation + "_" + stationName;
        int totalTime = travelData.getOrDefault(route, new Pair<>(0, 0)).getKey() + (t - startTime);
        int numTrips = travelData.getOrDefault(route, new Pair<>(0, 0)).getValue() + 1;
        travelData.put(route, new Pair<>(totalTime, numTrips));
    }

    public double getAverageTime(String startStation, String endStation) {
        String route = startStation + "_" + endStation;
        double totalTime = travelData.get(route).getKey();
        int numTrips = travelData.get(route).getValue();
        return totalTime / numTrips;
    }
}
